### Keyboard Shortcut Handling (lines 322-346)
```typescript
useEffect(() => {
  function handleKeyDown(e: KeyboardEvent) {
    if (e.key === 'k' && e.metaKey && viewMode !== 'form') {
      e.preventDefault();
      setActionsOpen(prev => !prev); // ⌘K toggles Actions dropdown
      return;
    }
    if (e.key === 'Enter' && e.metaKey && viewMode === 'form') {
      e.preventDefault();
      handleSubmitSnippet(); // ⌘↵ submits form
      return;
    }
    if (e.key === 'n' && e.metaKey && viewMode !== 'form') {
      e.preventDefault();
      handleOpenCreateSnippet(); // ⌘N opens snippet creator
    }
  }
  window.addEventListener('keydown', handleKeyDown);
  return () => window.removeEventListener('keydown', handleKeyDown);
}, [viewMode, handleSubmitSnippet, handleOpenCreateSnippet]);
```

