import { useCallback, useState } from 'react';
import type { AlertOptions } from '../components/alert/alert';

interface AlertState extends AlertOptions {
  resolve: (confirmed: boolean) => void;
}

export function useAlert() {
  const [alertState, setAlertState] = useState<AlertState | null>(null);

  const confirmAlert = useCallback(
    (options: AlertOptions): Promise<boolean> => {
      return new Promise<boolean>((resolve) => {
        const wrappedOptions: AlertState = {
          ...options,
          primaryAction: {
            ...options.primaryAction,
            onAction: () => {
              options.primaryAction.onAction();
              resolve(true);
            },
          },
          dismissAction: options.dismissAction
            ? {
                ...options.dismissAction,
                onAction: () => {
                  options.dismissAction!.onAction();
                  resolve(false);
                },
              }
            : {
                label: 'Cancel',
                style: 'cancel' as const,
                onAction: () => {
                  resolve(false);
                },
              },
          resolve,
        };
        setAlertState(wrappedOptions);
      });
    },
    [],
  );

  const dismiss = useCallback(() => {
    if (alertState) {
      alertState.resolve(false);
    }
    setAlertState(null);
  }, [alertState]);

  return {
    alertState,
    confirmAlert,
    dismiss,
  };
}

