        label: 'Open',
        shortcut: <Kbd keys={['↵']} />,
        onClick: () => {
          if (selectedItem) {
            showToast({
              style: 'success',
              title: `Opened ${selectedItem.title}`,
            });
          }
        },
      },
      {
        label: 'Copy Name',
        shortcut: (
          <Kbd
            keys={[
              '⌘',
              'C',
            ]}
          />
        ),
        onClick: () => {
          if (selectedItem) {
            showToast({
              style: 'info',
              title: 'Copied to clipboard',
              message: selectedItem.title,
            });
          }
        },
      },
      {
        label: 'Show Detail',
        shortcut: (
          <Kbd
            keys={[
              '⌘',
              'D',
            ]}
          />
        ),
        onClick: () => {
          showToast({
            style: 'info',
            title: 'Detail panel toggled',
          });
        },
      },
      {
        label: 'Create Snippet',
        shortcut: (
          <Kbd
            keys={[
              '⌘',
              'N',
            ]}
          />
        ),
        onClick: handleOpenCreateSnippet,
      },
      {
        label: 'Delete',
        shortcut: (
          <Kbd
            keys={[
              '⌘',
              '⌫',
            ]}
          />
        ),
        onClick: () => {
          showToast({
            style: 'error',
            title: 'Cannot delete',
            message: 'This item is read-only',
          });
        },
      },
    ],
    [
      selectedItem,
      showToast,
      handleOpenCreateSnippet,
    ],
  );

  const activeDescendantId =
    viewMode === 'grid'
      ? filteredColors.length > 0
        ? `grid-item-${selectedIndex}`
        : undefined
      : allItems.length > 0
        ? `list-item-${selectedIndex}`
        : undefined;

  return (
    <CommandPalette isLoading>
      <SearchBar
        value={query}
        onChange={handleQueryChange}
        activeDescendantId={activeDescendantId}
        breadcrumbs={breadcrumbs}
      />
      <div
        className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
      >
        <div className="command-palette__list-container">
          {viewMode === 'form' ? (
            <Form onSubmit={handleSubmitSnippet}>
              <FormTextField
                label="Name"
                value={snippetForm.name}
                onChange={v =>
                  setSnippetForm(prev => ({
                    ...prev,
                    name: v,
                  }))
                }
                placeholder="e.g. Email Signature"
                error={formErrors.name}
                autoFocus
              />
              <FormTextField
                label="Keyword"
                value={snippetForm.keyword}
                onChange={v =>
                  setSnippetForm(prev => ({
                    ...prev,
                    keyword: v,
                  }))
                }
                placeholder="e.g. !sig"
                description="Type this to expand the snippet"
              />
              <FormDropdown
                label="Category"
                value={snippetForm.category}
                onChange={v =>
                  setSnippetForm(prev => ({
                    ...prev,
                    category: v,
                  }))
                }
                options={SNIPPET_CATEGORIES}
                placeholder="Select a category"
              />
              <FormTextArea
                label="Snippet"
                value={snippetForm.snippet}
                onChange={v =>
                  setSnippetForm(prev => ({
                    ...prev,
                    snippet: v,
                  }))
                }
                placeholder="Enter your snippet content..."
                error={formErrors.snippet}
                rows={5}
              />
              <FormCheckbox
                label="Share with team"
                checked={snippetForm.isShared}
                onChange={v =>
                  setSnippetForm(prev => ({
                    ...prev,
                    isShared: v,
                  }))
                }
                description="Make this snippet available to your team members"
              />
              <FormDatePicker
                label="Expires"
                value={snippetForm.expiresAt}
                onChange={v =>
                  setSnippetForm(prev => ({
                    ...prev,
                    expiresAt: v,
                  }))
                }
                description="Optional expiration date"
              />
            </Form>
          ) : viewMode === 'grid' ? (
            filteredColors.length === 0 ? (
              <EmptyState
                icon={<SearchIcon />}
                title="No Colors"
                description="Try a different search term"
              />
            ) : (
              <Grid
                itemCount={filteredColors.length}
                columns={4}
                onActiveIndexChange={handleActiveIndexChange}
                onAction={handleGridAction}
              >
                {filteredColors.map((color, index) => (
                  <GridItem
                    key={color.id}
                    index={index}
                    icon={<ColorSwatch color={color.color} />}
                    title={color.title}
                    subtitle={color.subtitle}
                  />
                ))}
              </Grid>
            )
          ) : allItems.length === 0 ? (
            <EmptyState
              icon={<SearchIcon />}
              title="No Results"
              description="Try a different search term"
            />
          ) : (
            <List
              itemCount={allItems.length}
              onActiveIndexChange={handleActiveIndexChange}
              onAction={handleDrillIn}
            >
              {(() => {
                let globalIndex = 0;
                return filtered.map(section => (
                  <ListSection key={section.title} title={section.title}>
                    {section.items.map(item => {
                      const idx = globalIndex++;
                      return (
                        <ListItem
                          key={item.id}
                          index={idx}
                          title={item.title}
                          subtitle={item.subtitle}
                          icon={item.icon}
                          accessories={item.accessories}
                        />
                      );
                    })}
                  </ListSection>
                ));
              })()}
            </List>
          )}
        </div>
        {detail && (
          <Detail
            markdown={detail.markdown}
            metadata={
              detail.metadata ? (
                <DetailMetadata>
                  {detail.metadata.map(renderMetadataEntry)}
                </DetailMetadata>
              ) : undefined
            }
          />
        )}
      </div>
      <ActionPanel
        contextLabel={
          viewMode === 'form'
            ? 'Create Snippet'
            : viewMode === 'grid'
              ? 'Color Picker'
              : drilledItem
                ? drilledItem.title
                : 'Raycast'
        }
        actions={
          viewMode === 'form'
            ? [
                {
                  label: 'Submit',
                  shortcut: (
                    <Kbd
                      keys={[
                        '⌘',
                        '↵',
                      ]}
                    />
                  ),
                  onClick: handleSubmitSnippet,
                },
              ]
            : [
                {
                  label: 'Open',
                  shortcut: <Kbd keys={['↵']} />,
                },
                {
                  label: 'Actions',
                  shortcut: (
                    <Kbd
                      keys={[
                        '⌘',
                        'K',
                      ]}
                    />
                  ),
                  onClick: toggleActions,
                },
              ]
        }
        dropdownOpen={actionsOpen}
        dropdownActions={dropdownActions}
        onDropdownClose={closeActions}
      />
      <ToastContainer toasts={toasts} onDismiss={hideToast} />
    </CommandPalette>
  );
}

