import { useEffect, useRef, type ReactNode } from 'react';
import './alert.scss';

export type AlertActionStyle = 'default' | 'destructive' | 'cancel';

export interface AlertAction {
  label: string;
  style?: AlertActionStyle;
  onAction: () => void;
}

export interface AlertOptions {
  title: string;
  message?: string;
  icon?: ReactNode;
  primaryAction: AlertAction;
  dismissAction?: AlertAction;
}

interface AlertProps extends AlertOptions {
  onDismiss: () => void;
}

function AlertIcon({ icon }: { icon?: ReactNode }) {
  if (!icon) return null;
  return <div className="alert__icon">{icon}</div>;
}

export function Alert({
  title,
  message,
  icon,
  primaryAction,
  dismissAction,
  onDismiss,
}: AlertProps) {
  const dialogRef = useRef<HTMLDivElement>(null);
  const primaryRef = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    primaryRef.current?.focus();
  }, []);

  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === 'Escape') {
        e.preventDefault();
        e.stopPropagation();
        if (dismissAction) {
          dismissAction.onAction();
        }
        onDismiss();
        return;
      }
      if (e.key === 'Tab') {
        const focusable = dialogRef.current?.querySelectorAll<HTMLElement>(
          'button:not([disabled])',
        );
        if (!focusable || focusable.length === 0) return;

        const first = focusable.item(0);
        const last = focusable.item(focusable.length - 1);
        if (!first || !last) return;

        if (e.shiftKey) {
          if (document.activeElement === first) {
            e.preventDefault();
            last.focus();
          }
        } else {
          if (document.activeElement === last) {
            e.preventDefault();
            first.focus();
          }
        }
      }
    }

    window.addEventListener('keydown', handleKeyDown, true);
    return () => window.removeEventListener('keydown', handleKeyDown, true);
  }, [
    onDismiss,
    dismissAction,
  ]);

  function handleBackdropClick(e: React.MouseEvent) {
    if (e.target === e.currentTarget) {
      if (dismissAction) {
        dismissAction.onAction();
      }
      onDismiss();
    }
  }

  function handlePrimaryClick() {
    primaryAction.onAction();
    onDismiss();
  }

  function handleDismissClick() {
    if (dismissAction) {
      dismissAction.onAction();
    }
    onDismiss();
  }

  const primaryClassName = `alert__button alert__button--${primaryAction.style ?? 'default'}`;

  return (
    <div
      className="alert__backdrop"
      onClick={handleBackdropClick}
      role="presentation"
    >
      <div
        className="alert__dialog"
        ref={dialogRef}
        role="alertdialog"
        aria-modal="true"
        aria-labelledby="alert-title"
        aria-describedby={message ? 'alert-message' : undefined}
      >
        <AlertIcon icon={icon} />
        <h2 className="alert__title" id="alert-title">
          {title}
        </h2>
        {message && (
          <p className="alert__message" id="alert-message">
            {message}
          </p>
        )}
        <div className="alert__actions">
          {dismissAction && (
            <button
              type="button"
              className="alert__button alert__button--cancel"
              onClick={handleDismissClick}
            >
              {dismissAction.label}
            </button>
          )}
          <button
            type="button"
            className={primaryClassName}
            onClick={handlePrimaryClick}
            ref={primaryRef}
          >
            {primaryAction.label}
          </button>
        </div>
      </div>
    </div>
  );
}

