@use '../../styles/tokens' as *;

.alert__backdrop {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.4);
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  z-index: 200;
  border-radius: $radius-window;
  animation: alert-backdrop-enter $transition-normal ease-out both;
}

.alert__dialog {
  display: flex;
  flex-direction: column;
  align-items: center;
  width: 260px;
  padding: $space-5 $space-4 $space-4;
  background: $color-surface;
